-- Qortium HSQLDB schema baseline.
-- This starts fresh repositories at schema version 1 instead of replaying inherited Qortal migrations.
SET DATABASE SQL NAMES TRUE
SET DATABASE SQL SYNTAX MYS TRUE
SET DATABASE SQL RESTRICT EXEC TRUE
SET DATABASE TRANSACTION CONTROL MVCC
SET DATABASE DEFAULT TABLE TYPE CACHED
SET DATABASE COLLATION SQL_TEXT NO PAD
SET FILES SPACE TRUE
SET FILES WRITE DELAY 5
CREATE COLLATION PUBLIC.SQL_TEXT_UCC_NO_PAD FOR SQL_TEXT FROM SQL_TEXT_UCC NO PAD
CREATE COLLATION PUBLIC.SQL_TEXT_NO_PAD FOR SQL_TEXT FROM SQL_TEXT NO PAD
CREATE TYPE PUBLIC.ARBITRARYDATA AS VARBINARY(256)
CREATE TYPE PUBLIC.ASSETDATA AS VARCHAR(409600)
CREATE TYPE PUBLIC.ASSETID AS BIGINT
CREATE TYPE PUBLIC.ASSETNAME AS VARCHAR(34) COLLATE PUBLIC.SQL_TEXT_NO_PAD
CREATE TYPE PUBLIC.ASSETORDERID AS VARBINARY(64)
CREATE TYPE PUBLIC.ATCODE AS VARBINARY(8192)
CREATE TYPE PUBLIC.ATCREATIONBYTES AS VARBINARY(8192)
CREATE TYPE PUBLIC.ATMESSAGE AS VARBINARY(32)
CREATE TYPE PUBLIC.ATNAME AS VARCHAR(200) COLLATE PUBLIC.SQL_TEXT_UCC_NO_PAD
CREATE TYPE PUBLIC.ATSTATE AS VARBINARY(2048)
CREATE TYPE PUBLIC.ATTAGS AS VARCHAR(200) COLLATE PUBLIC.SQL_TEXT_UCC_NO_PAD
CREATE TYPE PUBLIC.ATTYPE AS VARCHAR(200) COLLATE PUBLIC.SQL_TEXT_UCC_NO_PAD
CREATE TYPE PUBLIC.ATSTATEHASH AS VARBINARY(32)
CREATE TYPE PUBLIC.BLOCKSIGNATURE AS VARBINARY(128)
CREATE TYPE PUBLIC.DATAHASH AS VARBINARY(32)
CREATE TYPE PUBLIC.EPOCHMILLIS AS BIGINT
CREATE TYPE PUBLIC.GENERICDESCRIPTION AS VARCHAR(4000)
CREATE TYPE PUBLIC.GROUPID AS INTEGER
CREATE TYPE PUBLIC.GROUPNAME AS VARCHAR(400) COLLATE PUBLIC.SQL_TEXT_UCC_NO_PAD
CREATE TYPE PUBLIC.GROUPREASON AS VARCHAR(128) COLLATE PUBLIC.SQL_TEXT_UCC_NO_PAD
CREATE TYPE PUBLIC.MESSAGEDATA AS VARBINARY(4000)
CREATE TYPE PUBLIC.NAMEDATA AS VARCHAR(4000)
CREATE TYPE PUBLIC.POLLNAME AS VARCHAR(400) COLLATE PUBLIC.SQL_TEXT_NO_PAD
CREATE TYPE PUBLIC.POLLOPTION AS VARCHAR(400) COLLATE PUBLIC.SQL_TEXT_UCC_NO_PAD
CREATE TYPE PUBLIC.POLLOPTIONINDEX AS SMALLINT
CREATE TYPE PUBLIC.ACCOUNTADDRESS AS VARCHAR(36)
CREATE TYPE PUBLIC.PRIVATEKEYSEED AS VARBINARY(32)
CREATE TYPE PUBLIC.ACCOUNTPUBLICKEY AS VARBINARY(32)
CREATE TYPE PUBLIC.ASSETAMOUNT AS BIGINT
CREATE TYPE PUBLIC.REGISTEREDNAME AS VARCHAR(128) COLLATE PUBLIC.SQL_TEXT_NO_PAD
CREATE TYPE PUBLIC.REWARDSHAREPERCENT AS INTEGER
CREATE TYPE PUBLIC.SIGNATURE AS VARBINARY(64)
CREATE TABLE PUBLIC.DATABASEINFO(VERSION INTEGER NOT NULL,AT_TRIM_HEIGHT INTEGER DEFAULT 0 NOT NULL,ONLINE_SIGNATURES_TRIM_HEIGHT INTEGER DEFAULT 0 NOT NULL,AT_PRUNE_HEIGHT INTEGER DEFAULT 0 NOT NULL,BLOCK_PRUNE_HEIGHT INTEGER DEFAULT 0 NOT NULL,BLOCK_ARCHIVE_HEIGHT INTEGER DEFAULT 0 NOT NULL,LATEST_SIGNATURE_POPULATED TINYINT DEFAULT 0 NOT NULL)
CREATE TABLE PUBLIC.BLOCKS(SIGNATURE PUBLIC.BLOCKSIGNATURE PRIMARY KEY,VERSION TINYINT NOT NULL,REFERENCE PUBLIC.BLOCKSIGNATURE,TRANSACTION_COUNT INTEGER NOT NULL,TOTAL_FEES PUBLIC.ASSETAMOUNT NOT NULL,TRANSACTIONS_SIGNATURE PUBLIC.SIGNATURE NOT NULL,HEIGHT INTEGER NOT NULL,MINTED_WHEN PUBLIC.EPOCHMILLIS NOT NULL,MINTER PUBLIC.ACCOUNTPUBLICKEY NOT NULL,MINTER_SIGNATURE PUBLIC.SIGNATURE NOT NULL,AT_COUNT INTEGER NOT NULL,AT_FEES PUBLIC.ASSETAMOUNT NOT NULL,ONLINE_ACCOUNTS VARBINARY(10240),ONLINE_ACCOUNTS_COUNT INTEGER NOT NULL,ONLINE_ACCOUNTS_TIMESTAMP PUBLIC.EPOCHMILLIS,ONLINE_ACCOUNTS_SIGNATURES VARBINARY(1048576))
CREATE INDEX BLOCKHEIGHTINDEX ON PUBLIC.BLOCKS(HEIGHT)
CREATE INDEX BLOCKMINTERINDEX ON PUBLIC.BLOCKS(MINTER)
CREATE INDEX BLOCKREFERENCEINDEX ON PUBLIC.BLOCKS(REFERENCE)
CREATE INDEX BLOCKTIMESTAMPHEIGHTINDEX ON PUBLIC.BLOCKS(MINTED_WHEN,HEIGHT)
CREATE TABLE PUBLIC.TRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,TYPE TINYINT NOT NULL,CREATOR PUBLIC.ACCOUNTPUBLICKEY NOT NULL,CREATED_WHEN PUBLIC.EPOCHMILLIS NOT NULL,FEE PUBLIC.ASSETAMOUNT NOT NULL,TX_GROUP_ID PUBLIC.GROUPID NOT NULL,NONCE INTEGER,BLOCK_HEIGHT INTEGER,APPROVAL_STATUS TINYINT NOT NULL,APPROVAL_HEIGHT INTEGER,BLOCK_SEQUENCE INTEGER)
CREATE INDEX TRANSACTIONTYPEINDEX ON PUBLIC.TRANSACTIONS(TYPE)
CREATE INDEX TRANSACTIONTIMESTAMPINDEX ON PUBLIC.TRANSACTIONS(CREATED_WHEN)
CREATE INDEX TRANSACTIONCREATORINDEX ON PUBLIC.TRANSACTIONS(CREATOR,TYPE)
CREATE INDEX TRANSACTIONGROUPINDEX ON PUBLIC.TRANSACTIONS(TX_GROUP_ID)
CREATE INDEX TRANSACTIONHEIGHTINDEX ON PUBLIC.TRANSACTIONS(BLOCK_HEIGHT)
CREATE INDEX TRANSACTIONAPPROVALSTATUSINDEX ON PUBLIC.TRANSACTIONS(APPROVAL_STATUS,BLOCK_HEIGHT)
CREATE INDEX TRANSACTIONAPPROVALHEIGHTINDEX ON PUBLIC.TRANSACTIONS(APPROVAL_HEIGHT)
CREATE INDEX TRANSACTIONHEIGHTSEQUENCEINDEX ON PUBLIC.TRANSACTIONS(BLOCK_HEIGHT,BLOCK_SEQUENCE)
CREATE TABLE PUBLIC.BLOCKTRANSACTIONS(BLOCK_SIGNATURE PUBLIC.BLOCKSIGNATURE,SEQUENCE INTEGER,TRANSACTION_SIGNATURE PUBLIC.SIGNATURE,PRIMARY KEY(BLOCK_SIGNATURE,SEQUENCE),UNIQUE(TRANSACTION_SIGNATURE),FOREIGN KEY(TRANSACTION_SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE,FOREIGN KEY(BLOCK_SIGNATURE) REFERENCES PUBLIC.BLOCKS(SIGNATURE) ON DELETE CASCADE)
CREATE TABLE PUBLIC.UNCONFIRMEDTRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,CREATED_WHEN PUBLIC.EPOCHMILLIS NOT NULL)
CREATE INDEX UNCONFIRMEDTRANSACTIONSINDEX ON PUBLIC.UNCONFIRMEDTRANSACTIONS(CREATED_WHEN,SIGNATURE)
CREATE TABLE PUBLIC.TRANSACTIONPARTICIPANTS(SIGNATURE PUBLIC.SIGNATURE NOT NULL,PARTICIPANT PUBLIC.ACCOUNTADDRESS NOT NULL,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE INDEX TRANSACTIONPARTICIPANTSADDRESSINDEX ON PUBLIC.TRANSACTIONPARTICIPANTS(PARTICIPANT)
CREATE TABLE PUBLIC.ACCOUNTS(ACCOUNT PUBLIC.ACCOUNTADDRESS PRIMARY KEY,PUBLIC_KEY PUBLIC.ACCOUNTPUBLICKEY,DEFAULT_GROUP_ID PUBLIC.GROUPID DEFAULT 0 NOT NULL,LEVEL INTEGER DEFAULT 0 NOT NULL,BLOCKS_MINTED INTEGER DEFAULT 0 NOT NULL)
CREATE INDEX ACCOUNTPUBLICKEYINDEX ON PUBLIC.ACCOUNTS(PUBLIC_KEY)
CREATE TABLE PUBLIC.ACCOUNTAVATARS(ACCOUNT PUBLIC.ACCOUNTADDRESS PRIMARY KEY,AVATAR_SIGNATURE PUBLIC.SIGNATURE NOT NULL,FOREIGN KEY(ACCOUNT) REFERENCES PUBLIC.ACCOUNTS(ACCOUNT) ON DELETE CASCADE)
CREATE TABLE PUBLIC.ACCOUNTBALANCES(ACCOUNT PUBLIC.ACCOUNTADDRESS,ASSET_ID PUBLIC.ASSETID,BALANCE PUBLIC.ASSETAMOUNT NOT NULL,PRIMARY KEY(ACCOUNT,ASSET_ID),FOREIGN KEY(ACCOUNT) REFERENCES PUBLIC.ACCOUNTS(ACCOUNT) ON DELETE CASCADE,CONSTRAINT CHECKBALANCENOTNEGATIVE CHECK(PUBLIC.ACCOUNTBALANCES.BALANCE>=0))
CREATE INDEX ACCOUNTBALANCESASSETBALANCEINDEX ON PUBLIC.ACCOUNTBALANCES(ASSET_ID,BALANCE)
CREATE TABLE PUBLIC.GENESISTRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,RECIPIENT PUBLIC.ACCOUNTADDRESS NOT NULL,AMOUNT PUBLIC.ASSETAMOUNT NOT NULL,ASSET_ID PUBLIC.ASSETID NOT NULL,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE TABLE PUBLIC.SHAREDTRANSACTIONPAYMENTS(SIGNATURE PUBLIC.SIGNATURE,RECIPIENT PUBLIC.ACCOUNTADDRESS NOT NULL,AMOUNT PUBLIC.ASSETAMOUNT NOT NULL,ASSET_ID PUBLIC.ASSETID NOT NULL,PAYMENT_INDEX INTEGER NOT NULL,PRIMARY KEY(SIGNATURE,PAYMENT_INDEX),FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE INDEX SHAREDTRANSACTIONPAYMENTSRECIPIENTINDEX ON PUBLIC.SHAREDTRANSACTIONPAYMENTS(RECIPIENT,SIGNATURE)
CREATE TABLE PUBLIC.PAYMENTTRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,SENDER PUBLIC.ACCOUNTPUBLICKEY NOT NULL,RECIPIENT PUBLIC.ACCOUNTADDRESS NOT NULL,AMOUNT PUBLIC.ASSETAMOUNT NOT NULL,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE INDEX PAYMENTTRANSACTIONSRECIPIENTINDEX ON PUBLIC.PAYMENTTRANSACTIONS(RECIPIENT)
CREATE TABLE PUBLIC.MULTIPAYMENTTRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,SENDER PUBLIC.ACCOUNTPUBLICKEY NOT NULL,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE TABLE PUBLIC.MESSAGETRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,VERSION TINYINT NOT NULL,NONCE INTEGER NOT NULL,SENDER PUBLIC.ACCOUNTPUBLICKEY NOT NULL,RECIPIENT PUBLIC.ACCOUNTADDRESS,AMOUNT PUBLIC.ASSETAMOUNT NOT NULL,ASSET_ID PUBLIC.ASSETID,IS_TEXT BOOLEAN NOT NULL,IS_ENCRYPTED BOOLEAN NOT NULL,DATA PUBLIC.MESSAGEDATA NOT NULL,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE INDEX MESSAGETRANSACTIONSRECIPIENTINDEX ON PUBLIC.MESSAGETRANSACTIONS(RECIPIENT,SENDER)
CREATE TABLE PUBLIC.ARBITRARYTRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,SENDER PUBLIC.ACCOUNTPUBLICKEY NOT NULL,VERSION TINYINT NOT NULL,SERVICE SMALLINT NOT NULL,IS_DATA_RAW BOOLEAN NOT NULL,DATA PUBLIC.ARBITRARYDATA NOT NULL,NONCE INTEGER DEFAULT 0 NOT NULL,SIZE INTEGER DEFAULT 0 NOT NULL,METADATA_HASH VARBINARY(32),NAME PUBLIC.REGISTEREDNAME,UPDATE_METHOD INTEGER DEFAULT 0 NOT NULL,SECRET VARBINARY(32),COMPRESSION INTEGER DEFAULT 0 NOT NULL,IDENTIFIER VARCHAR(64),CREATED_WHEN PUBLIC.EPOCHMILLIS NOT NULL,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE INDEX ARBITRARYDATAINDEX ON PUBLIC.ARBITRARYTRANSACTIONS(IS_DATA_RAW,DATA)
CREATE INDEX ARBITRARYNAMEINDEX ON PUBLIC.ARBITRARYTRANSACTIONS(NAME)
CREATE INDEX ARBITRARYNAMECREATEDINDEX ON PUBLIC.ARBITRARYTRANSACTIONS(NAME,CREATED_WHEN DESC)
CREATE INDEX ARBITRARYSERVICEINDEX ON PUBLIC.ARBITRARYTRANSACTIONS(SERVICE)
CREATE INDEX ARBITRARYIDENTIFIERINDEX ON PUBLIC.ARBITRARYTRANSACTIONS(IDENTIFIER)
CREATE TABLE PUBLIC.NAMES(NAME PUBLIC.REGISTEREDNAME PRIMARY KEY,REDUCED_NAME PUBLIC.REGISTEREDNAME,OWNER PUBLIC.ACCOUNTADDRESS NOT NULL,REGISTERED_WHEN PUBLIC.EPOCHMILLIS NOT NULL,UPDATED_WHEN PUBLIC.EPOCHMILLIS,IS_FOR_SALE BOOLEAN DEFAULT FALSE NOT NULL,SALE_PRICE PUBLIC.ASSETAMOUNT,SALE_RECIPIENT PUBLIC.ACCOUNTADDRESS,DATA PUBLIC.NAMEDATA NOT NULL,REFERENCE PUBLIC.SIGNATURE,CREATION_GROUP_ID PUBLIC.GROUPID DEFAULT 0 NOT NULL)
CREATE INDEX NAMESOWNERINDEX ON PUBLIC.NAMES(OWNER)
CREATE INDEX NAMESREDUCEDNAMEINDEX ON PUBLIC.NAMES(REDUCED_NAME)
CREATE TABLE PUBLIC.REGISTERNAMETRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,REGISTRANT PUBLIC.ACCOUNTPUBLICKEY NOT NULL,NAME PUBLIC.REGISTEREDNAME NOT NULL,DATA PUBLIC.NAMEDATA NOT NULL,REDUCED_NAME PUBLIC.REGISTEREDNAME NOT NULL,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE INDEX REGISTERNAMENAMEINDEX ON PUBLIC.REGISTERNAMETRANSACTIONS(NAME)
CREATE INDEX REGISTERNAMEREDUCEDNAMEINDEX ON PUBLIC.REGISTERNAMETRANSACTIONS(REDUCED_NAME)
CREATE TABLE PUBLIC.UPDATENAMETRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,OWNER PUBLIC.ACCOUNTPUBLICKEY NOT NULL,NAME PUBLIC.REGISTEREDNAME NOT NULL,NEW_NAME PUBLIC.REGISTEREDNAME NOT NULL,NEW_DATA PUBLIC.NAMEDATA NOT NULL,IS_PRIMARY BOOLEAN,REDUCED_NEW_NAME PUBLIC.REGISTEREDNAME NOT NULL,PREVIOUS_PRIMARY_NAME PUBLIC.REGISTEREDNAME,NAME_REFERENCE PUBLIC.SIGNATURE,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE INDEX UPDATENAMENAMEINDEX ON PUBLIC.UPDATENAMETRANSACTIONS(NAME)
CREATE INDEX UPDATENAMENEWNAMEINDEX ON PUBLIC.UPDATENAMETRANSACTIONS(NEW_NAME)
CREATE INDEX UPDATENAMEREDUCEDNEWNAMEINDEX ON PUBLIC.UPDATENAMETRANSACTIONS(REDUCED_NEW_NAME)
CREATE TABLE PUBLIC.SELLNAMETRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,OWNER PUBLIC.ACCOUNTPUBLICKEY NOT NULL,NAME PUBLIC.REGISTEREDNAME NOT NULL,AMOUNT PUBLIC.ASSETAMOUNT NOT NULL,RECIPIENT PUBLIC.ACCOUNTADDRESS,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE INDEX SELLNAMENAMEINDEX ON PUBLIC.SELLNAMETRANSACTIONS(NAME)
CREATE TABLE PUBLIC.CANCELSELLNAMETRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,OWNER PUBLIC.ACCOUNTPUBLICKEY NOT NULL,NAME PUBLIC.REGISTEREDNAME NOT NULL,SALE_PRICE PUBLIC.ASSETAMOUNT,SALE_RECIPIENT PUBLIC.ACCOUNTADDRESS,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE TABLE PUBLIC.BUYNAMETRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,BUYER PUBLIC.ACCOUNTPUBLICKEY NOT NULL,NAME PUBLIC.REGISTEREDNAME NOT NULL,SELLER PUBLIC.ACCOUNTADDRESS NOT NULL,AMOUNT PUBLIC.ASSETAMOUNT NOT NULL,NAME_REFERENCE PUBLIC.SIGNATURE,SALE_RECIPIENT PUBLIC.ACCOUNTADDRESS,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE INDEX BUYNAMENAMEINDEX ON PUBLIC.BUYNAMETRANSACTIONS(NAME)
CREATE TABLE PUBLIC.CREATEPOLLTRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,CREATOR PUBLIC.ACCOUNTPUBLICKEY NOT NULL,OWNER PUBLIC.ACCOUNTADDRESS NOT NULL,POLL_NAME PUBLIC.POLLNAME NOT NULL,DESCRIPTION PUBLIC.GENERICDESCRIPTION NOT NULL,POLL_ID INTEGER,START_WHEN PUBLIC.EPOCHMILLIS,END_WHEN PUBLIC.EPOCHMILLIS,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE TABLE PUBLIC.CREATEPOLLTRANSACTIONOPTIONS(SIGNATURE PUBLIC.SIGNATURE,OPTION_INDEX PUBLIC.POLLOPTIONINDEX NOT NULL,OPTION_NAME PUBLIC.POLLOPTION,PRIMARY KEY(SIGNATURE,OPTION_INDEX),FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.CREATEPOLLTRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE TABLE PUBLIC.VOTEONPOLLTRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,VOTER PUBLIC.ACCOUNTPUBLICKEY NOT NULL,OPTION_INDEX PUBLIC.POLLOPTIONINDEX NOT NULL,PREVIOUS_OPTION_INDEX PUBLIC.POLLOPTIONINDEX,POLL_ID INTEGER NOT NULL,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE TABLE PUBLIC.VOTEONPOLLTRANSACTIONOPTIONS(SIGNATURE PUBLIC.SIGNATURE,OPTION_INDEX PUBLIC.POLLOPTIONINDEX NOT NULL,PRIMARY KEY(SIGNATURE,OPTION_INDEX),FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.VOTEONPOLLTRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE TABLE PUBLIC.VOTEONPOLLTRANSACTIONPREVIOUSOPTIONS(SIGNATURE PUBLIC.SIGNATURE,OPTION_INDEX PUBLIC.POLLOPTIONINDEX NOT NULL,PRIMARY KEY(SIGNATURE,OPTION_INDEX),FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.VOTEONPOLLTRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE TABLE PUBLIC.ASSETS(ASSET_ID PUBLIC.ASSETID PRIMARY KEY,OWNER PUBLIC.ACCOUNTADDRESS NOT NULL,ASSET_NAME PUBLIC.ASSETNAME NOT NULL,DESCRIPTION PUBLIC.GENERICDESCRIPTION NOT NULL,QUANTITY BIGINT NOT NULL,IS_DIVISIBLE BOOLEAN NOT NULL,IS_UNSPENDABLE BOOLEAN DEFAULT FALSE NOT NULL,CREATION_GROUP_ID PUBLIC.GROUPID DEFAULT 0 NOT NULL,REFERENCE PUBLIC.SIGNATURE NOT NULL,DATA PUBLIC.ASSETDATA DEFAULT '' NOT NULL,REDUCED_ASSET_NAME PUBLIC.ASSETNAME NOT NULL,IS_OWNER_FOR_SALE BOOLEAN DEFAULT FALSE NOT NULL,OWNER_SALE_PRICE PUBLIC.ASSETAMOUNT,OWNER_SALE_RECIPIENT PUBLIC.ACCOUNTADDRESS)
CREATE INDEX ASSETNAMEINDEX ON PUBLIC.ASSETS(ASSET_NAME)
CREATE INDEX ASSETREDUCEDNAMEINDEX ON PUBLIC.ASSETS(REDUCED_ASSET_NAME)
CREATE TABLE PUBLIC.ASSETORDERS(ASSET_ORDER_ID PUBLIC.ASSETORDERID PRIMARY KEY,CREATOR PUBLIC.ACCOUNTPUBLICKEY NOT NULL,HAVE_ASSET_ID PUBLIC.ASSETID NOT NULL,WANT_ASSET_ID PUBLIC.ASSETID NOT NULL,AMOUNT PUBLIC.ASSETAMOUNT NOT NULL,FULFILLED PUBLIC.ASSETAMOUNT NOT NULL,PRICE PUBLIC.ASSETAMOUNT NOT NULL,ORDERED_WHEN PUBLIC.EPOCHMILLIS NOT NULL,IS_CLOSED BOOLEAN NOT NULL,IS_FULFILLED BOOLEAN NOT NULL)
CREATE INDEX ASSETORDERMATCHINGINDEX ON PUBLIC.ASSETORDERS(HAVE_ASSET_ID,WANT_ASSET_ID,IS_CLOSED,IS_FULFILLED,PRICE,ORDERED_WHEN)
CREATE INDEX ASSETORDERCREATORINDEX ON PUBLIC.ASSETORDERS(CREATOR,IS_CLOSED)
CREATE TABLE PUBLIC.ASSETTRADES(INITIATING_ORDER_ID PUBLIC.ASSETORDERID NOT NULL,TARGET_ORDER_ID PUBLIC.ASSETORDERID NOT NULL,TARGET_AMOUNT PUBLIC.ASSETAMOUNT NOT NULL,INITIATOR_AMOUNT PUBLIC.ASSETAMOUNT NOT NULL,TRADED_WHEN PUBLIC.EPOCHMILLIS NOT NULL,INITIATOR_SAVING PUBLIC.ASSETAMOUNT DEFAULT 0 NOT NULL)
CREATE INDEX ASSETTRADEBUYORDERINDEX ON PUBLIC.ASSETTRADES(INITIATING_ORDER_ID,TRADED_WHEN)
CREATE INDEX ASSETTRADESELLORDERINDEX ON PUBLIC.ASSETTRADES(TARGET_ORDER_ID,TRADED_WHEN)
CREATE TABLE PUBLIC.ISSUEASSETTRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,ISSUER PUBLIC.ACCOUNTPUBLICKEY NOT NULL,ASSET_NAME PUBLIC.ASSETNAME NOT NULL,DESCRIPTION PUBLIC.GENERICDESCRIPTION NOT NULL,QUANTITY BIGINT NOT NULL,IS_DIVISIBLE BOOLEAN NOT NULL,ASSET_ID PUBLIC.ASSETID,REQUESTED_ASSET_ID PUBLIC.ASSETID,IS_UNSPENDABLE BOOLEAN NOT NULL,DATA PUBLIC.ASSETDATA DEFAULT '' NOT NULL,REDUCED_ASSET_NAME PUBLIC.ASSETNAME NOT NULL,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE TABLE PUBLIC.TRANSFERASSETTRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,SENDER PUBLIC.ACCOUNTPUBLICKEY NOT NULL,RECIPIENT PUBLIC.ACCOUNTADDRESS NOT NULL,ASSET_ID PUBLIC.ASSETID NOT NULL,AMOUNT PUBLIC.ASSETAMOUNT NOT NULL,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE TABLE PUBLIC.UPDATEASSETTRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,OWNER PUBLIC.ACCOUNTPUBLICKEY NOT NULL,ASSET_ID PUBLIC.ASSETID NOT NULL,NEW_NAME PUBLIC.ASSETNAME NOT NULL,NEW_DESCRIPTION PUBLIC.GENERICDESCRIPTION NOT NULL,NEW_DATA PUBLIC.ASSETDATA NOT NULL,REDUCED_NEW_NAME PUBLIC.ASSETNAME NOT NULL,ORPHAN_REFERENCE PUBLIC.SIGNATURE,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE TABLE PUBLIC.SELLASSETOWNERSHIPTRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,OWNER PUBLIC.ACCOUNTPUBLICKEY NOT NULL,ASSET_ID PUBLIC.ASSETID NOT NULL,AMOUNT PUBLIC.ASSETAMOUNT NOT NULL,RECIPIENT PUBLIC.ACCOUNTADDRESS,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE TABLE PUBLIC.CANCELSELLASSETOWNERSHIPTRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,OWNER PUBLIC.ACCOUNTPUBLICKEY NOT NULL,ASSET_ID PUBLIC.ASSETID NOT NULL,SALE_PRICE PUBLIC.ASSETAMOUNT,SALE_RECIPIENT PUBLIC.ACCOUNTADDRESS,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE TABLE PUBLIC.BUYASSETOWNERSHIPTRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,BUYER PUBLIC.ACCOUNTPUBLICKEY NOT NULL,ASSET_ID PUBLIC.ASSETID NOT NULL,AMOUNT PUBLIC.ASSETAMOUNT NOT NULL,SELLER PUBLIC.ACCOUNTADDRESS NOT NULL,ASSET_REFERENCE PUBLIC.SIGNATURE,SALE_RECIPIENT PUBLIC.ACCOUNTADDRESS,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE TABLE PUBLIC.CREATEASSETORDERTRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,CREATOR PUBLIC.ACCOUNTPUBLICKEY NOT NULL,HAVE_ASSET_ID PUBLIC.ASSETID NOT NULL,AMOUNT PUBLIC.ASSETAMOUNT NOT NULL,WANT_ASSET_ID PUBLIC.ASSETID NOT NULL,PRICE PUBLIC.ASSETAMOUNT NOT NULL,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE TABLE PUBLIC.CANCELASSETORDERTRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,CREATOR PUBLIC.ACCOUNTPUBLICKEY NOT NULL,ASSET_ORDER_ID PUBLIC.ASSETORDERID NOT NULL,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE TABLE PUBLIC.ATS(AT_ADDRESS PUBLIC.ACCOUNTADDRESS PRIMARY KEY,CREATOR PUBLIC.ACCOUNTPUBLICKEY NOT NULL,CREATED_WHEN PUBLIC.EPOCHMILLIS NOT NULL,VERSION INTEGER NOT NULL,ASSET_ID PUBLIC.ASSETID NOT NULL,CODE_BYTES VARBINARY(8192) NOT NULL,CODE_HASH VARBINARY(32) NOT NULL,CREATION_GROUP_ID PUBLIC.GROUPID DEFAULT 0 NOT NULL,IS_SLEEPING BOOLEAN NOT NULL,SLEEP_UNTIL_HEIGHT INTEGER,IS_FINISHED BOOLEAN NOT NULL,HAD_FATAL_ERROR BOOLEAN NOT NULL,IS_FROZEN BOOLEAN NOT NULL,FROZEN_BALANCE PUBLIC.ASSETAMOUNT,SLEEP_UNTIL_MESSAGE_TIMESTAMP BIGINT)
CREATE TABLE PUBLIC.ATMAPENTRIES(AT_ADDRESS PUBLIC.ACCOUNTADDRESS NOT NULL,KEY1 BIGINT NOT NULL,KEY2 BIGINT NOT NULL,"VALUE" BIGINT NOT NULL CHECK("VALUE"<>0),PRIMARY KEY(AT_ADDRESS,KEY1,KEY2),FOREIGN KEY(AT_ADDRESS) REFERENCES PUBLIC.ATS(AT_ADDRESS) ON DELETE CASCADE)
CREATE TABLE PUBLIC.ATMAPENTRYCHANGES(HEIGHT INTEGER NOT NULL,SEQUENCE INTEGER NOT NULL,AT_ADDRESS PUBLIC.ACCOUNTADDRESS NOT NULL,KEY1 BIGINT NOT NULL,KEY2 BIGINT NOT NULL,PREVIOUS_VALUE BIGINT,NEW_VALUE BIGINT,CHECK(PREVIOUS_VALUE IS NULL OR PREVIOUS_VALUE<>0),CHECK(NEW_VALUE IS NULL OR NEW_VALUE<>0),PRIMARY KEY(HEIGHT,SEQUENCE),FOREIGN KEY(AT_ADDRESS) REFERENCES PUBLIC.ATS(AT_ADDRESS) ON DELETE CASCADE)
CREATE INDEX ATMAPENTRYCHANGESADDRESSKEYINDEX ON PUBLIC.ATMAPENTRYCHANGES(AT_ADDRESS,KEY1,KEY2,HEIGHT)
CREATE INDEX ATINDEX ON PUBLIC.ATS(IS_FINISHED,CREATED_WHEN)
CREATE INDEX ATCREATORINDEX ON PUBLIC.ATS(CREATOR)
CREATE INDEX ATCODEHASHINDEX ON PUBLIC.ATS(CODE_HASH,IS_FINISHED)
CREATE TABLE PUBLIC.DEPLOYATTRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,CREATOR PUBLIC.ACCOUNTPUBLICKEY NOT NULL,AT_NAME VARCHAR(200) COLLATE PUBLIC.SQL_TEXT_UCC_NO_PAD NOT NULL,DESCRIPTION PUBLIC.GENERICDESCRIPTION NOT NULL,AT_TYPE VARCHAR(200) COLLATE PUBLIC.SQL_TEXT_UCC_NO_PAD NOT NULL,AT_TAGS VARCHAR(200) COLLATE PUBLIC.SQL_TEXT_UCC_NO_PAD NOT NULL,CREATION_BYTES VARBINARY(8192) NOT NULL,AMOUNT PUBLIC.ASSETAMOUNT NOT NULL,ASSET_ID PUBLIC.ASSETID NOT NULL,NATIVE_FEE_RESERVE PUBLIC.ASSETAMOUNT DEFAULT 0 NOT NULL,AT_ADDRESS PUBLIC.ACCOUNTADDRESS,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE INDEX DEPLOYATADDRESSINDEX ON PUBLIC.DEPLOYATTRANSACTIONS(AT_ADDRESS)
CREATE TABLE PUBLIC.ATTRANSACTIONS(SIGNATURE PUBLIC.SIGNATURE PRIMARY KEY,AT_ADDRESS PUBLIC.ACCOUNTADDRESS NOT NULL,RECIPIENT PUBLIC.ACCOUNTADDRESS,AMOUNT PUBLIC.ASSETAMOUNT,ASSET_ID PUBLIC.ASSETID,MESSAGE PUBLIC.ATMESSAGE,FOREIGN KEY(SIGNATURE) REFERENCES PUBLIC.TRANSACTIONS(SIGNATURE) ON DELETE CASCADE)
CREATE INDEX ATTRANSACTIONSINDEX ON PUBLIC.ATTRANSACTIONS(AT_ADDRESS)
CREATE INDEX ATTRANSACTIONSRECIPIENTINDEX ON PUBLIC.ATTRANSACTIONS(RECIPIENT)
CREATE TABLE PUBLIC."GROUPS"(GROUP_ID PUBLIC.GROUPID PRIMARY KEY,OWNER PUBLIC.ACCOUNTADDRESS NOT NULL,GROUP_NAME PUBLIC.GROUPNAME NOT NULL,CREATED_WHEN PUBLIC.EPOCHMILLIS NOT NULL,UPDATED_WHEN PUBLIC.EPOCHMILLIS,IS_OPEN BOOLEAN NOT NULL,APPROVAL_THRESHOLD TINYINT NOT NULL,MIN_BLOCK_DELAY INTEGER NOT NULL,MAX_BLOCK_DELAY INTEGER NOT NULL,REFERENCE PUBLIC.SIGNATURE,CREATION_GROUP_ID PUBLIC.GROUPID,REDUCED_GROUP_NAME PUBLIC.GROUPNAME NOT NULL,DESCRIPTION PUBLIC.GENERICDESCRIPTION NOT NULL,AVATAR_SIGNATURE PUBLIC.SIGNATURE)
CREATE INDEX GROUPNAMEINDEX ON PUBLIC."GROUPS"(GROUP_NAME)
CREATE INDEX GROUPREDUCEDNAMEINDEX ON PUBLIC."GROUPS"(REDUCED_GROUP_NAME)
CREATE INDEX GROUPOWNERINDEX ON PUBLIC."GROUPS"(OWNER)
CREATE TABLE PUBLIC.GROUPADMINS(GROUP_ID PUBLIC.GROUPID,ADMIN PUBLIC.ACCOUNTADDRESS,REFERENCE PUBLIC.SIGNATURE NOT NULL,PRIMARY KEY(GROUP_ID,ADMIN),FOREIGN KEY(GROUP_ID) REFERENCES PUBLIC."GROUPS"(GROUP_ID) ON DELETE CASCADE)
CREATE INDEX GROUPADMININDEX ON PUBLIC.GROUPADMINS(ADMIN)
CREATE TABLE PUBLIC.GROUPMEMBERS(GROUP_ID PUBLIC.GROUPID,ADDRESS PUBLIC.ACCOUNTADDRESS,JOINED_WHEN PUBLIC.EPOCHMILLIS NOT NULL,REFERENCE PUBLIC.SIGNATURE NOT NULL,PRIMARY KEY(GROUP_ID,ADDRESS),FOREIGN KEY(GROUP_ID) REFERENCES PUBLIC."GROUPS"(GROUP_ID) ON DELETE CASCADE)
CREATE INDEX GROUPMEMBERINDEX ON PUBLIC.GROUPMEMBERS(ADDRESS)
CREATE TABLE PUBLIC.GROUPINVITES(GROUP_ID PUBLIC.GROUPID,INVITER PUBLIC.ACCOUNTADDRESS,INVITEE PUBLIC.ACCOUNTADDRESS,EXPIRES_WHEN PUBLIC.EPOCHMILLIS,REFERENCE PUBLIC.SIGNATURE,PRIMARY KEY(GROUP_ID,INVITEE),FOREIGN KEY(GROUP_ID) REFERENCES PUBLIC."GROUPS"(GROUP_ID) ON DELETE CASCADE)
CREATE INDEX GROUPINVITEINVITERINDEX ON PUBLIC.GROUPINVITES(INVITER)
CREATE INDEX GROUPINVITEINVITEEINDEX ON PUBLIC.GROUPINVITES(INVITEE)
CREATE INDEX GROUPINVITEEXPIRYINDEX ON PUBLIC.GROUPINVITES(EXPIRES_WHEN)
CREATE TABLE PUBLIC.GROUPJOINREQUESTS(GROUP_ID PUBLIC.GROUPID,JOINER PUBLIC.ACCOUNTADDRESS,REFERENCE PUBLIC.SIGNATURE NOT NULL,PRIMARY KEY(GROUP_ID,JOINER))
CREATE TABLE PUBLIC.GROUPBANS(GROUP_ID PUBLIC.GROUPID,OFFENDER PUBLIC.ACCOUNTADDRESS,ADMIN PUBLIC.ACCOUNTADDRESS NOT NULL,BANNED_WHEN PUBLIC.EPOCHMILLIS NOT NULL,REASON PUBLIC.GENERICDESCRIPTION NOT NULL,EXPIRES_WHEN PUBLIC.EPOCHMILLIS,REFERENCE PUBLIC.SIGNATURE NOT NULL,PRIMARY KEY(GROUP_ID,OFFENDER),FOREIGN KEY(GROUP_ID) REFERENCES PUBLIC."GROUPS"(GROUP_ID) ON DELETE CASCADE)
