SET SCHEMA PUBLIC
CREATE TRIGGER PUBLIC.ASSET_ID_TRIGGER BEFORE INSERT ON PUBLIC.ASSETS REFERENCING NEW ROW AS NEW_ROW FOR EACH ROW WHEN (new_row.asset_id IS NULL) SET NEW_ROW.ASSET_ID=(SELECT IFNULL(MAX(ASSET_ID)+1,1)FROM PUBLIC.ASSETS WHERE ASSET_ID>=1)
CREATE TRIGGER PUBLIC.GROUP_ID_TRIGGER BEFORE INSERT ON PUBLIC."GROUPS" REFERENCING NEW ROW AS NEW_ROW FOR EACH ROW WHEN (new_row.group_id IS NULL) SET NEW_ROW.GROUP_ID=(SELECT IFNULL(MAX(GROUP_ID)+1,1)FROM PUBLIC."GROUPS")
CREATE TRIGGER PUBLIC.POLL_ID_TRIGGER BEFORE INSERT ON PUBLIC.POLLS REFERENCING NEW ROW AS NEW_ROW FOR EACH ROW WHEN (new_row.poll_id IS NULL) SET NEW_ROW.POLL_ID=(SELECT IFNULL(MAX(POLL_ID)+1,1)FROM PUBLIC.POLLS)
INSERT INTO DATABASEINFO VALUES(5,0,0,0,0,0,0)
